import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';
import { HttpClientModule } from '@angular/common/http';
import { AppRoutingModule } from './app-routing.module';
import { RouterModule } from '@angular/router';
import { AppComponent } from './app.component';
import { NavbarComponent } from './components/navbar/navbar.component';

import { BaseChartDirective, provideCharts, withDefaultRegisterables } from 'ng2-charts';
import { ReactiveFormsModule, FormsModule } from '@angular/forms';
import { DashboardComponent } from './features/dashboard/dashboard.component';
import { SidebarComponent } from './components/components/sidebar/sidebar.component';
import { AppointmentComponent } from './features/appointment/appointment.component'; // ✅ مستورد هنا
import { PatientComponent } from './features/patient/patient.component';
import { StaffComponent } from './features/staff/staff.component';
import { LabComponent } from './features/lab/lab.component';
import { LoginComponent } from './login/login.component';
import { DoctorComponent } from './features/doctor/doctor.component';
import { DashboardLayoutComponent } from './dashboard-layout/dashboard-layout.component';
import { InvoiceComponent } from './features/invoice/invoice.component';
import { PharmacyComponent } from './features/pharmacy/pharmacy.component';
import { AppointmentComponent } from './appointment/appointment.component';
@NgModule({
  declarations: [
    AppComponent,
    DashboardComponent,
    SidebarComponent,
    // ❌ تم حذف AppointmentComponent من هنا لأنه Standalone
    DashboardLayoutComponent,
    InvoiceComponent,
    PharmacyComponent,
    AppointmentComponent,
  ],
  imports: [
    BrowserModule,
    HttpClientModule,
    AppRoutingModule,
    ReactiveFormsModule,
    RouterModule,
    FormsModule,
    BaseChartDirective,
    NavbarComponent,
    StaffComponent,
    PatientComponent,
    LabComponent,
    LoginComponent,
    DoctorComponent,
    AppointmentComponent, // ✅ تم إضافته هنا في الـ imports ليعمل الـ Selector
  ],
  providers: [provideCharts(withDefaultRegisterables())],
  bootstrap: [AppComponent]
})
export class AppModule { }
